public String shiftCharacters(String s, int[][] shifts) {
    int[] shiftValues = new int[s.length()];
    for (int[] shift : shifts) {
        int start = shift[0], end = shift[1], direction = shift[2];
        int value = (direction == 1) ? 1 : -1;
        shiftValues[start] += value;
        if (end + 1 < s.length()) shiftValues[end + 1] -= value;
    }

    for (int i = 1; i < s.length(); i++) {
        shiftValues[i] += shiftValues[i - 1];
    }

    char[] sArray = s.toCharArray();
    for (int i = 0; i < s.length(); i++) {
        sArray[i] = (char) ((sArray[i] - 'a' + shiftValues[i]) % 26 + 'a');
    }

    return new String(sArray);
}
```

